  1	import * as React from 'react';
  2	import { DiscoveredDevice } from '@odf/core/types/scale';
  3	import { DASH, useCustomTranslation } from '@odf/shared';
  4	import { TableSkeletonLoader } from '@odf/shared/skeletal-loader/TableSkeleton';
  5	import { humanizeBinaryBytes } from '@odf/shared/utils';
  6	import {
  7	  ListPageFilter,
  8	  useListPageFilter,
  9	} from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Table,
 12	  Tbody,
 13	  Td,
 14	  Th,
 15	  Thead,
 16	  Tr,
 17	  OnSelect,
 18	  SortByDirection,
 19	} from '@patternfly/react-table';
 20	import './LUNsTable.scss';
 21	
 22	type LUNsTableProps = {
 23	  luns: DiscoveredDevice[];
 24	  selectedLUNs: Set<string>;
 25	  onLUNSelect: (selectedLUNs: Set<string>) => void;
 26	  loaded?: boolean;
 27	};
 28	
 29	export const LUNsTable: React.FC<LUNsTableProps> = ({
 30	  luns,
 31	  selectedLUNs,
 32	  onLUNSelect,
 33	  loaded = true,
 34	}) => {
 35	  const { t } = useCustomTranslation();
 36	  const [sortBy, setSortBy] = React.useState<{
 37	    index: number;
 38	    direction: SortByDirection;
 39	  }>({ index: 1, direction: SortByDirection.asc });
 40	
 41	  const sortedLUNs = React.useMemo(() => {
 42	    const sorted = [...luns];
 43	    sorted.sort((a, b) => {
 44	      let aValue: string | number;
 45	      let bValue: string | number;
 46	
 47	      switch (sortBy.index) {
 48	        case 0: // Path
 49	          aValue = a.path;
 50	          bValue = b.path;
 51	          break;
 52	        case 1: // WWID
 53	          aValue = a.WWN || '';
 54	          bValue = b.WWN || '';
 55	          break;
 56	        case 2: // Capacity
 57	          aValue = a.size || 0;
 58	          bValue = b.size || 0;
 59	          break;
 60	        default:
 61	          return 0;
 62	      }
 63	
 64	      const comparison =
 65	        typeof aValue === 'string' && typeof bValue === 'string'
 66	          ? aValue.localeCompare(bValue)
 67	          : typeof aValue === 'number' && typeof bValue === 'number'
 68	            ? aValue - bValue
 69	            : String(aValue).localeCompare(String(bValue));
 70	
 71	      return sortBy.direction === SortByDirection.asc
 72	        ? comparison
 73	        : -comparison;
 74	    });
 75	    return sorted;
 76	  }, [luns, sortBy]);
 77	
 78	  const handleSort = React.useCallback(
 79	    (
 80	      _event: React.MouseEvent,
 81	      columnIndex: number,
 82	      direction: SortByDirection
 83	    ) => {
 84	      setSortBy({ index: columnIndex, direction });
 85	    },
 86	    []
 87	  );
 88	
 89	  const areAllSelected = React.useMemo(() => {
 90	    return luns.length > 0 && luns.every((lun) => selectedLUNs.has(lun.WWN));
 91	  }, [luns, selectedLUNs]);
 92	
 93	  const handleSelectAll: OnSelect = React.useCallback(
 94	    (_event, isSelected) => {
 95	      const newSelected = new Set(selectedLUNs);
 96	      if (isSelected) {
 97	        luns.forEach((lun) => newSelected.add(lun.WWN));
 98	      } else {
 99	        luns.forEach((lun) => newSelected.delete(lun.WWN));
100	      }
101	      onLUNSelect(newSelected);
102	    },
103	    [luns, selectedLUNs, onLUNSelect]
104	  );
105	
106	  const handleRowSelect: OnSelect = React.useCallback(
107	    (_event, isSelected, rowIndex, rowData) => {
108	      // rowIndex is -1 for select all, otherwise it's the row index
109	      if (rowIndex === -1) {
110	        // This is select all - should not happen for individual row selection
111	        return;
112	      }
113	
114	      // Use rowData.props.id if available (more reliable than rowIndex)
115	      const lunWWID =
116	        rowData?.props?.id ||
117	        (rowIndex >= 0 && rowIndex < sortedLUNs.length
118	          ? sortedLUNs[rowIndex]?.WWN
119	          : null);
120	
121	      if (!lunWWID) {
122	        return;
123	      }
124	
125	      const newSelected = new Set(selectedLUNs);
126	      if (isSelected) {
127	        newSelected.add(lunWWID);
128	      } else {
129	        newSelected.delete(lunWWID);
130	      }
131	      onLUNSelect(newSelected);
132	    },
133	    [sortedLUNs, selectedLUNs, onLUNSelect]
134	  );
135	
136	  const [lunsData, lunsFilteredData, onLunsFilterChange] = useListPageFilter(
137	    sortedLUNs.map((lun) => ({ ...lun, metadata: { name: lun.path } })),
138	    []
139	  );
140	  if (!loaded) {
141	    return <TableSkeletonLoader columns={4} rows={5} />;
142	  }
143	
144	  return (
145	    <div className="odf-luns-table">
146	      <ListPageFilter
147	        data={lunsData}
148	        loaded={loaded}
149	        onFilterChange={onLunsFilterChange}
150	        hideColumnManagement={true}
151	      />
152	      <div className="odf-luns-table__body-container">
153	        <Table
154	          variant="compact"
155	          aria-label={t('LUNs table')}
156	          className="odf-luns-table__table"
157	        >
158	          <Thead>
159	            <Tr>
160	              <Th
161	                select={{
162	                  onSelect: handleSelectAll,
163	                  isSelected: areAllSelected,
164	                }}
165	                aria-label={t('Select all')}
166	              />
167	              <Th
168	                sort={{
169	                  sortBy: sortBy,
170	                  onSort: handleSort,
171	                  columnIndex: 0,
172	                }}
173	              >
174	                {t('Path')}
175	              </Th>
176	              <Th
177	                sort={{
178	                  sortBy: sortBy,
179	                  onSort: handleSort,
180	                  columnIndex: 1,
181	                }}
182	              >
183	                {t('WWID')}
184	              </Th>
185	              <Th
186	                sort={{
187	                  sortBy: sortBy,
188	                  onSort: handleSort,
189	                  columnIndex: 2,
190	                }}
191	              >
192	                {t('Capacity')}
193	              </Th>
194	            </Tr>
195	          </Thead>
196	          <Tbody>
197	            {lunsFilteredData.map((lun, index) => (
198	              <Tr key={lun.WWN || lun.path}>
199	                <Td
200	                  select={{
201	                    rowIndex: index,
202	                    onSelect: handleRowSelect,
203	                    isSelected: selectedLUNs.has(lun.WWN),
204	                    props: {
205	                      id: lun.WWN,
206	                    },
207	                  }}
208	                />
209	                <Td>{lun.path}</Td>
210	                <Td>{lun.WWN || DASH}</Td>
211	                <Td>{humanizeBinaryBytes(lun.size).string || '-'}</Td>
212	              </Tr>
213	            ))}
214	          </Tbody>
215	        </Table>
216	      </div>
217	    </div>
218	  );
219	};

